CREATE OR REPLACE FUNCTION S0045874.Issue_Age(vDateOfBirth date, vIssue_Date date, vXNL varchar(2))
RETURNS numeric AS $$
DECLARE
  Inforce_Month numeric;
  tmp numeric;
BEGIN
  IF $3 = 'L' THEN
    RETURN Trunc(months_between($2, $1) / 12);
  ELSIF $3 = 'N' THEN
    RETURN Round(months_between($2, $1) / 12);
  ELSIF $3 = 'X' THEN
    RETURN Trunc(months_between($2, $1) / 12) + 1;
  ELSIF $3 = 'Q' THEN
    Inforce_Month := Trunc(months_between($2, $1)) + 1;
    tmp := Trunc((Inforce_Month+11)/12);

    IF mod(Inforce_Month,12) between 1 and 3 THEN
      tmp := tmp - 0.75;
    ELSIF mod(Inforce_Month,12) between 1 and 6 THEN
      tmp := tmp - 0.5;
    ELSIF mod(Inforce_Month,12) between 1 and 9 THEN
      tmp := tmp - 0.25;
    END IF;

    RETURN tmp;
  ELSIF $3 = 'H' THEN
    Inforce_Month := Trunc(months_between($2, $1)) + 1;
    tmp := Trunc((Inforce_Month+11)/12); -- IssueAge using Half Year Next Birthday method
    IF mod(Inforce_Month,12) between 1 and 6 THEN
      tmp := tmp - 0.5;
    END IF;
    RETURN tmp;
  ELSE
    RETURN -1;
  END IF;
END;
$$ LANGUAGE plpgsql;
