Here is an example of sending an email using .Net Core and configuring the SMTP server, port, and other settings from a configuration file:
```csharp
using System;
using System.Net;
using System.Net.Mail;
using Microsoft.Extensions.Configuration;

namespace EmailExample
{
    class Program
    {
        static void Main(string[] args)
        {
            // Load configuration settings
            var configuration = new ConfigurationBuilder()
                .AddJsonFile("appsettings.json")
                .Build();

            var smtpServer = configuration.GetValue<string>("SmtpServer");
            var port = configuration.GetValue<int>("SmtpPort");
            var from = configuration.GetValue<string>("FromEmail");
            var to = configuration.GetValue<string>("ToEmail");
            var password = configuration.GetValue<string>("Password");

            // Create a new mail message
            var message = new MailMessage(from, to)
            {
                Subject = "Test Email",
                Body = "This is a test email sent from .Net Core.",
                IsBodyHtml = false
            };

            // Set up the SMTP client
            var client = new SmtpClient(smtpServer)
            {
                Port = port,
                DeliveryMethod = SmtpDeliveryMethod.Network,
                UseDefaultCredentials = false,
                Credentials = new NetworkCredential(from, password),
                EnableSsl = true
            };

            // Send the email
            client.Send(message);

            Console.WriteLine("Email sent successfully.");
        }
    }
}
```
