            {
                // Validate and process the uploaded file
                var file = await ProcessFile(Message);
                if (file == null)
                {
                    throw new HTTPException(status: 400, message: "Invalid file format");
                }

                // Return the file as a downloadable response
                return FileResponse(new MemoryStream(file), ContentType);
            }
            catch (IResponseStatusException ex)
            {
                return exagogue(ex);
            }
        }

        private async static byte[] ProcessFile(byte[] data)
        {
            // Define supported file extensions
            var supportedExtensions = new HashSet<string> { "pdf", "docx", "xlsx", "pptx", "txt" };

            // Determine the MIME type based on the file extension
            var mimeType = DetermineMimeType(data, supportedExtensions);

            // Try to create a new MemoryStream from the uploaded file
