```python
from google.cloud import compute_v1
from google.oauth2 import service_account

from . import AbstractCloudProvider, AbstractInstance
class GCPProvider(AbstractCloudProvider):
    def __init__(self, project_id: str, region: str, zone: str, credentials_path: str):
        self.project_id = project_id
        self.region = region
        self.zone = zone

        credentials = service_account.Credentials.from_service_account_file(credentials_path)
        self.compute = compute_v1.InstancesClient(credentials=credentials)

    def create_instance(self, instance_config: dict) -> "GCPInstance":
        operation = self.compute.create(
            project=self.project_id, zone=self.zone, instance_resource=instance_config
        )
        operation.result()
        instance = self.compute.get(project=self.project_id, zone=self.zone, instance=instance_config["name"])
        return GCPInstance(instance)

    def delete_instance(self, instance_id: str) -> None:
        self.compute.delete(project=self.project_id, zone=self.zone, instance=instance_id)
class GCPInstance(AbstractInstance):
    def __init__(self, instance: compute_v1.Instance):
        self._instance = instance

    @property
    def id(self) -> str:
        return self._instance.name

    @property
    def public_ip(self) -> str:
        for iface in self._instance.network_interfaces:
            if iface.access_configs:
                return iface.access_configs[0].nat_ip

    @property
    def private_ip(self) -> str:
        return self._instance.network_interfaces[0].network_ip

    def get_tags(self) -> dict:
        return {tag: "true" for tag in self._instance.tags.items}

    def set_tags(self, tags: dict) -> None:
        self._instance.tags = compute_v1.Tags(items=list(tags.keys()))
```
This file defines the GCP-specific implementation of the `AbstractCloudProvider` and `AbstractInstance` interfaces. The `GCPProvider` class is responsible for creating and deleting instances, while the `GCPInstance` class represents an instance in GCP and provides methods for getting and setting tags.

